    async def list(
        self, *, active: typing.Optional[bool] = None, request_options: typing.Optional[RequestOptions] = None
    ) -> BulkSyncListEnvelope:
        """
        Lists bulk syncs in the caller's organization.

        Results are ordered by `updated_at` descending, with `id` as a tiebreaker for
        syncs modified at the same instant. Pagination uses an opaque
        `pagination.next_page_token` returned in the response; pass it back as the
        `page_token` query parameter to fetch the next page. The `limit` parameter is
        optional, and the default and maximum page size is 50 syncs.

        > 📘 To retrieve a specific sync, use
        > [`GET /api/bulk/syncs/{id}`](../../../api-reference/bulk-sync/get)
        > instead of filtering the list client-side.

        Parameters
        ----------
        active : typing.Optional[bool]
            Filter to only active (true) or only paused (false) syncs. Omit to return both.

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        BulkSyncListEnvelope
            OK

        Examples
        --------
        import asyncio

        from polytomic import AsyncPolytomic

        client = AsyncPolytomic(
            "2025-09-18",
            token="YOUR_TOKEN",
        )


        async def main() -> None:
            await client.bulk_sync.list(
                active=True,
            )


        asyncio.run(main())
        """
        _response = await self._raw_client.list(active=active, request_options=request_options)
        return _response.data

    async def create(
        self,
        *,
        default_schedule: BulkSyncDefaultScheduleRequest,
        destination_configuration: typing.Dict[str, typing.Any],
        destination_connection_id: str,
        name: str,
        source_connection_id: str,
        active: typing.Optional[bool] = OMIT,
        additional_schedules: typing.Optional[typing.Sequence[BulkSyncAdditionalScheduleRequest]] = OMIT,
        automatically_add_new_fields: typing.Optional[BulkDiscover] = OMIT,
        automatically_add_new_objects: typing.Optional[BulkDiscover] = OMIT,
        concurrency_limit: typing.Optional[int] = OMIT,
        data_cutoff_timestamp: typing.Optional[dt.datetime] = OMIT,
        disable_record_timestamps: typing.Optional[bool] = OMIT,
        mode: typing.Optional[BulkSyncTargetMode] = OMIT,
        normalize_names: typing.Optional[BulkNormalizeNames] = OMIT,
        organization_id: typing.Optional[str] = OMIT,
        policies: typing.Optional[typing.Sequence[str]] = OMIT,
        resync_concurrency_limit: typing.Optional[int] = OMIT,
        schemas: typing.Optional[typing.Sequence[CreateBulkSyncRequestSchemasItem]] = OMIT,
        source_configuration: typing.Optional[typing.Dict[str, typing.Any]] = OMIT,
        idempotency_key: typing.Optional[str] = None,
        request_options: typing.Optional[RequestOptions] = None,
    ) -> BulkSyncResponseEnvelope:
        """
        Creates a new bulk sync.

        Bulk syncs are used for the ELT pattern (Extract, Load, and Transform), where you want to sync un-transformed data to your data warehouses, databases, or cloud storage buckets like S3.

        All of the functionality described in [the product
        documentation](https://docs.polytomic.com/docs/bulk-syncs) is configurable via
        the API.

        Sample code examples:

        - [Bulk sync (ELT) from Salesforce to S3](../../../guides/code-examples/bulk-sync-elt-from-salesforce-to-s-3)
        - [Bulk sync (ELT) from Salesforce to Snowflake](../../../guides/code-examples/bulk-sync-elt-from-salesforce-to-snowflake)
        - [Bulk sync (ELT) from HubSpot to PostgreSQL](../../../guides/code-examples/bulk-sync-elt-from-hub-spot-to-postgre-sql)

        ## Connection specific configuration

        The `destination_configuration` is integration-specific configuration for the
        selected bulk sync destination. This includes settings such as the output schema
        and is required when creating a new sync.

        The `source_configuration` is optional. It allows configuration for how
        Polytomic reads data from the source connection. This will not be available for
        integrations that do not support additional configuration.

        Consult the [connection configurations](../../../guides/configuring-your-connections/overview)
        to see configurations for particular integrations (for example, [here](../../../guides/configuring-your-connections/connections/postgre-sql#source-1) is the available source configuration for the PostgreSQL bulk sync source).

        ## Defaults and selection behavior

        If `schemas` is omitted, the sync is created with all available source schemas
        selected. Pass `schemas` explicitly if you want the initial sync to include
        only a subset of tables or objects.

        Schedule times are interpreted in UTC.

        When omitted, automatic discovery defaults are conservative:

        - `automatically_add_new_objects` defaults to not enabling newly discovered
          source objects automatically.
        - `automatically_add_new_fields` defaults to enabling newly discovered fields
          on already selected objects.
        - `normalize_names` defaults to enabled.

        Parameters
        ----------
        default_schedule : BulkSyncDefaultScheduleRequest

        destination_configuration : typing.Dict[str, typing.Any]
            Destination-specific bulk sync configuration (e.g. output schema name, file format). The accepted keys depend on the destination connection type.

        destination_connection_id : str
            Unique identifier of the connection rows are written to.

        name : str
            Human-readable name for the bulk sync.

        source_connection_id : str
            Unique identifier of the connection rows are read from.

        active : typing.Optional[bool]
            Whether the sync is active. Inactive syncs do not run on their schedule but can still be triggered manually.

        additional_schedules : typing.Optional[typing.Sequence[BulkSyncAdditionalScheduleRequest]]
            Additional bulk sync schedules. Schedule times are interpreted in UTC.

        automatically_add_new_fields : typing.Optional[BulkDiscover]

        automatically_add_new_objects : typing.Optional[BulkDiscover]

        concurrency_limit : typing.Optional[int]
            Override the default concurrency limit for this sync.

        data_cutoff_timestamp : typing.Optional[dt.datetime]
            Global cutoff applied across schemas. Source records older than this timestamp are excluded from sync runs.

        disable_record_timestamps : typing.Optional[bool]
            When true, Polytomic will not add its own timestamp columns to destination rows.

        mode : typing.Optional[BulkSyncTargetMode]

        normalize_names : typing.Optional[BulkNormalizeNames]

        organization_id : typing.Optional[str]
            Organization the sync is created in. Only used by partner callers; normal callers always create syncs in their own organization.

        policies : typing.Optional[typing.Sequence[str]]
            Identifiers of permissions policies applied to the bulk sync.

        resync_concurrency_limit : typing.Optional[int]
            Override the default resync concurrency limit for this sync.

        schemas : typing.Optional[typing.Sequence[CreateBulkSyncRequestSchemasItem]]
            List of schemas to sync; if omitted, all schemas will be selected for syncing.

        source_configuration : typing.Optional[typing.Dict[str, typing.Any]]
            Source-specific bulk sync configuration (e.g. replication slot name, sync lookback). The accepted keys depend on the source connection type.

        idempotency_key : typing.Optional[str]

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        BulkSyncResponseEnvelope
            OK

        Examples
        --------
        import asyncio

        from polytomic import AsyncPolytomic, BulkSyncDefaultScheduleRequest

        client = AsyncPolytomic(
            "2025-09-18",
            token="YOUR_TOKEN",
        )


        async def main() -> None:
            await client.bulk_sync.create(
                default_schedule=BulkSyncDefaultScheduleRequest(
                    frequency="manual",
                ),
                destination_configuration={"schema": "my_schema"},
                destination_connection_id="248df4b7-aa70-47b8-a036-33ac447e668d",
                name="My Bulk Sync",
                source_connection_id="248df4b7-aa70-47b8-a036-33ac447e668d",
            )


        asyncio.run(main())
        """
        _response = await self._raw_client.create(
            default_schedule=default_schedule,
            destination_configuration=destination_configuration,
            destination_connection_id=destination_connection_id,
            name=name,
            source_connection_id=source_connection_id,
            active=active,
            additional_schedules=additional_schedules,
            automatically_add_new_fields=automatically_add_new_fields,
            automatically_add_new_objects=automatically_add_new_objects,
            concurrency_limit=concurrency_limit,
            data_cutoff_timestamp=data_cutoff_timestamp,
            disable_record_timestamps=disable_record_timestamps,
            mode=mode,
            normalize_names=normalize_names,
            organization_id=organization_id,
            policies=policies,
            resync_concurrency_limit=resync_concurrency_limit,
            schemas=schemas,
            source_configuration=source_configuration,
            idempotency_key=idempotency_key,
            request_options=request_options,
        )
        return _response.data

